#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return *(int*)a - *(int*)b;}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *arr = (int*)malloc(N*sizeof(int));
        int impossible = 0;
        for(int i=0;i<N;i++){
            scanf("%d", &arr[i]);
            if(arr[i] > N) impossible = 1;
        }
        if(impossible){
            printf("-1\n");
            free(arr);
            continue;
        }
        qsort(arr, N, sizeof(int), cmp);
        long long ops = 0;
        int cur = 1;
        for(int i=0;i<N;i++){
            if(cur < arr[i]) cur = arr[i];
            if(cur > N){ impossible = 1; break; }
            ops += cur - arr[i];
            cur++;
        }
        if(impossible) printf("-1\n");
        else printf("%lld\n", ops);
        free(arr);
    }
    return 0;
}

